sql:
SELECT seats.seat_id, lodges.lodge_name 
FROM seats
INNER JOIN lodges ON seats.lodge = lodges.lodge_id;

SELECT c.customer_name, ci.inquiry_type, ci.response_status
FROM customers c
JOIN customer_inquiries ci ON c.customer_id = ci.customer_id;

SELECT price 
FROM ticket_sales 
WHERE sale_date = '2023-11-15';

SELECT e.event_id, e.event_name, ts.seat_id
FROM events e
JOIN ticket_sales ts ON e.event_id = ts.event_id;

external_knowledge:
- "sailing across the seas" metaphorically refers to artists performing in different venues; 
- "harbors" refers to the lodges in which performances take place;
- "collect the most treasure" metaphorically means generating the most revenue;
- "most valuable treasures" refers to the highest total revenue.

sql:
SELECT event_id, COUNT(seat_id) AS seeds
FROM ticket_sales
GROUP BY event_id;

SELECT lodge, seat_type_id, COUNT(seat_id) AS seat_count
FROM seats
GROUP BY lodge, seat_type_id;

SELECT lodge_name 
FROM lodges 
WHERE lodge_id = 1;

SELECT seat_id, lodge, row, number, seat_type_id, price
FROM seats
WHERE price > (SELECT AVG(price) FROM seats);
